const TAU = 6.283;
const PHI = 1.618;
const SQRT_HALF = 0.707;

const config = {
  attraction: 4000,
  springCoeff: 0.004,
  amplification: 0.92,
  centerDrift: 0.0003,
  streamLimit: 40,
  streamDecay: 0.04,
